var _ models.Validator = (*CreateWebhookInput)(nil)
func (i CreateWebhookInput) Validate() error {
    var errs []error
    if i.Namespace == "" { errs = append(errs, errors.New("namespace is required")) }
    return NewValidationError(errors.Join(errs...))
}

